#include <cstdio>
#include <ctime>
#include <cstdlib>

int main()
{
    srand(time(NULL));
    int tries = 0, myNum = 0, min = 0, max = 101;
    int findNum;
    puts("Welcome to Ace's Guessing Game!");
    puts("In this version, the computer tries to guess your number.");
    std::cout<<"Enter a number between 1 and 100 (Warning: Bad input causes program to terminate!): ";
    std::cin>>myNum;
    if(std::cin.fail()) //catches bad input strings and things that wont convert 
    {
        puts("Input error occured. Quitting.");
        return 0;
    }else if(std::cin.bad()) //catches the case where a user just presses the enter key 
    {
        puts("Input error occured. Quitting.");
        return 0;
    }else if(myNum < (min+1)) //obviously going below the min value 
    {
        puts("Input error occured. Quitting.");
        return 0; 
    }else if(myNum > (max-1)) //again obviously, going above max value 
    {
        puts("Input error occured. Quitting.");
        return 0;
    }

    do //now that all error cases have been handled, time for the fun 
    {
        findNum = rand() % ((max + 1) - min) + min;

        std::cout << "\nComputer's guess: " << findNum << std::endl;
        ++tries;

        if(myNum > findNum)
        {
           std::cout << "Too low!\n";
           min = findNum + 1;
        }else if(myNum < findNum)
        {
           std::cout << "Too high!\n";
           max = findNum - 1;
        }else
            std::cout << "Computer found the number in " << tries << " tries.";
    }while(myNum != findNum);
    return 0;
